generated_oml:
// Sensing components
instance MotorCurrentSensor : DTDFVocab:SensingComponent [
   base:desc "Permanent‑magnet synchronous motor current sensor on axis 1"
   DTDFVocab:producedData I_M_Topic
]

instance MotorRotaryEncoder : DTDFVocab:SensingComponent [
   base:desc "Dual encoder on motor shaft for axis 1 providing position and velocity"
   DTDFVocab:producedData MotorPosition_Topic
]

instance GearboxRotaryEncoder : DTDFVocab:SensingComponent [
   base:desc "Dual encoder on gearbox shaft for axis 1 providing position and velocity"
   DTDFVocab:producedData GearboxPosition_Topic
]

// Data being transmitted over MQTT
instance I_M_Topic : DTDFVocab:DataTransmitted [
   DTDFVocab:producedFrom MotorCurrentSensor
]

instance MotorPosition_Topic : DTDFVocab:DataTransmitted [
   DTDFVocab:producedFrom MotorRotaryEncoder
]

instance GearboxPosition_Topic : DTDFVocab:DataTransmitted [
   DTDFVocab:producedFrom GearboxRotaryEncoder
]

// Raw data derived from transmitted messages
instance MotorCurrentData : DTDFVocab:Data [
   base:desc "Motor current value I_M received from MQTT"
   DTDFVocab:fromData I_M_Topic
   DTDFVocab:inputTo DataProcessingEnabler
]

instance MotorPositionData : DTDFVocab:Data [
   base:desc "Motor angular position θ_M received from MQTT"
   DTDFVocab:fromData MotorPosition_Topic
   DTDFVocab:inputTo DataProcessingEnabler
]

instance GearboxPositionData : DTDFVocab:Data [
   base:desc "Gearbox angular position θ_G received from MQTT"
   DTDFVocab:fromData GearboxPosition_Topic
   DTDFVocab:inputTo DataProcessingEnabler
]

// Enablers
instance DataProcessingEnabler : DTDFVocab:Enabler [
   base:desc "Engine executing MATLAB‑Simulink models and data‑calculation algorithms"
   DTDFVocab:enables FrictionModelIdentificationService, DashboardVisualizationService, DataAggregationService
]

instance MQTTSubscriberEnabler : DTDFVocab:Enabler [
   base:desc "MQTT subscriber that receives live sensor streams for the axis 1 digital shadow"
   DTDFVocab:enables DataProcessingEnabler
]

// Models
instance MotorSimulationModel : DTDFVocab:Model [
   base:desc "Matlab‑Simulink model of the permanent‑magnet synchronous motor with friction blocks"
   DTDFVocab:inputTo DataProcessingEnabler
]

instance GearwheelSimulationModel : DTDFVocab:Model [
   base:desc "Simulink model representing the gearwheel gearbox including Coulomb‑Viscous friction"
   DTDFVocab:inputTo DataProcessingEnabler
]

instance CycloidalGearboxSimulationModel : DTDFVocab:Model [
   base:desc "Simulink model of the cycloidal gearbox with Stribeck friction representation"
   DTDFVocab:inputTo DataProcessingEnabler
]

instance FrictionParameterEstimationModel : DTDFVocab:Model [
   base:desc "Multi‑physics black‑box model that estimates joint friction parameters (Dahl, LuGre, etc.)"
   DTDFVocab:inputTo DataProcessingEnabler
]

instance AssetAdministrationShellModel : DTDFVocab:Model [
   base:desc "Versioned AAS defining asset metadata and model provenance for axis 1"
   DTDFVocab:inputTo DataProcessingEnabler
]

// Services
instance FrictionModelIdentificationService : DTDFVocab:Service [
   base:desc "Continuous identification of white‑box and black‑box friction models for the joint"
   DTDFVocab:provides FrictionParameterEstimationInsight
]

instance DashboardVisualizationService : DTDFVocab:Service [
   base:desc "Real‑time dashboard comparing measured joint kinematics with simulated traces"
   DTDFVocab:provides ResidualAnalysisInsight, WearPhaseDetectionInsight
]

instance DataAggregationService : DTDFVocab:Service [
   base:desc "Aggregates raw sensor streams and model outputs for operator insight"
   DTDFVocab:provides MaintenanceDecisionSupportInsight
]

// Insights
instance FrictionParameterEstimationInsight : DTDFVocab:Insight [
   base:desc "Real‑time estimation of joint friction parameters to refine the control model"
]

instance WearPhaseDetectionInsight : DTDFVocab:Insight [
   base:desc "Detection of wear phases in the gearbox based on residual analysis"
]

instance ResidualAnalysisInsight : DTDFVocab:Insight [
   base:desc "Visualization of residuals between measured and simulated joint kinematics"
]

instance MaintenanceDecisionSupportInsight : DTDFVocab:Insight [
   base:desc "Decision support information for maintenance planning of the axis 1 drive"
]

// Actions
instance UpdateControlModelAction : DTDFVocab:Action [
   base:desc "Automatic update of the control model using newly estimated friction parameters"
   DTDFVocab:IsAutomatic true
]

instance ScheduleMaintenanceAction : DTDFVocab:Action [
   base:desc "Scheduled maintenance based on wear phase detection"
   DTDFVocab:IsAutomatic false
]

instance ProvideOperatorGuidanceAction : DTDFVocab:Action [
   base:desc "Guidance for operator interventions derived from dashboard alerts"
   DTDFVocab:IsAutomatic false
]

// Environment
instance Axis1DigitalTwinEnvironment : DTDFVocab:Environment [
   base:contains Axis1Component
]

// Components
instance Axis1Component : DTDFVocab:Component [
   base:desc "Digital twin of the first rotational axis of MABI MAX 100 robot"
]

instance twinning_time_scale : DTDFVocab:TimeScale [
    base:desc "Real‑time, continuous ingestion and processing of live data streams during robot operation – the digital shadow is continuously updated, but no explicit sampling frequency is specified in the document."
]

instance dt_constellation : DTDFVocab:Constellation [
    base:desc "A data ingestion pipeline where sensor streams are received via MQTT, stored in a time‑series database; processing component consumes raw traces, executes simulation and data‑calculation models to produce abstracted traces; dashboard visualizes real‑time data; Asset Administration Shell orchestrates asset metadata, linking traces to models; overall constellation follows a purpose‑driven architecture."
]

instance life_cycle_stages : DTDFVocab:EvolutionStage [
    base:desc "Operated stage – the digital shadow is created and updated during live operation of the robot, continuously adapting to changes from wear, temperature, and load."
]

instance fidelity_and_validity_considerations : DTDFVocab:FidelityConsideration [
    base:desc "White‑box analytical friction models parameterized by load, temperature, time; black‑box data‑driven models reduce explicit parameters; traceability maintained via processing component linking raw data to model outputs; validation performed by comparing simulated outputs (r_M, r_G, r_out) with measured traces; uncertainties from wear, tool changes acknowledged; multi‑physics approach ensures fidelity across mechanical, electrical, and thermal domains."
]

instance dt_technical_connection : DTDFVocab:TechnicalConnection [
    base:desc "Sensor data streams are transmitted from the robot to the digital shadow using MQTT. The Siemens SINUMERIK 840D CNC controller supplies motor current and encoder positions as inputs; the digital shadow processes these inputs but no further low‑level networking details are provided."
]

instance standardization : DTDFVocab:Standardization [
    base:desc "Use of SysML (v1.7) for modeling; UML class diagrams for reference models; Asset Administration Shell (AAS) for contextual data; adherence to Kritzinger et al. digital shadow definition; complementing MBSE methodologies such as RFLP, OOSEM, and SMArDT."
]
